1	interface Item {
2	  type: string;
3	  material?: string;
4	  enchantment?: number;
5	  cursed?: boolean;
6	}
7	
8	interface QuoteStep {
9	  op: "quote";
10	  items: Item[];
11	}
12	
13	interface Customer {
14	  yearsWithMHPCO: number;
15	}
16	
17	interface Scenario {
18	  customer: Customer;
19	  steps: QuoteStep[];
20	}
21	
22	const MAIN_ITEM_BASE: Record<string, number> = {
23	  sword: 100,
24	  amulet: 60,
25	  staff: 80,
26	  potion: 40,
27	};
28	
29	const COMPONENT_TYPES = new Set(["rune", "moonstone"]);
30	const COMPONENT_BASE = 25;
31	const BLOCK_SIZE = 3;
32	const BLOCK_BASE = 60;
33	
34	const PROCESSING_FEE = 5;
35	const FIRST_INSURANCE_SURCHARGE_RATE = 0.1;
36	const CURSED_SURCHARGE_RATE = 0.5;
37	
38	const componentGroupBase = (count: number): number => {
39	  if (count === BLOCK_SIZE) return BLOCK_BASE;
40	  return count * COMPONENT_BASE;
41	};
42	
43	const isComponent = (item: Item): boolean => COMPONENT_TYPES.has(item.type);
44	
45	const sumMainItems = (items: Item[]): number =>
46	  items
47	    .filter((item) => !isComponent(item))
48	    .reduce((total, item) => total + MAIN_ITEM_BASE[item.type], 0);
49	
50	const countByType = (items: Item[]): Record<string, number> => {
51	  const counts: Record<string, number> = {};
52	  for (const item of items) {
53	    counts[item.type] = (counts[item.type] ?? 0) + 1;
54	  }
55	  return counts;
56	};
57	
58	const sumComponentGroups = (items: Item[]): number => {
59	  const counts = countByType(items.filter(isComponent));
60	  return Object.values(counts).reduce((total, count) => total + componentGroupBase(count), 0);
61	};
62	
63	const policyBasePremium = (items: Item[]): number =>
64	  sumMainItems(items) + sumComponentGroups(items);
65	
66	const itemSurcharges = (items: Item[]): number =>
67	  items
68	    .filter((item) => !isComponent(item))
69	    .reduce((total, item) => {
70	      const base = MAIN_ITEM_BASE[item.type];
71	      return total + (item.cursed ? base * CURSED_SURCHARGE_RATE : 0);
72	    }, 0);
73	
74	const quotePremium = (step: QuoteStep): number => {
75	  const base = policyBasePremium(step.items);
76	  const withFirstInsurance = base + base * FIRST_INSURANCE_SURCHARGE_RATE;
77	  return Math.ceil(withFirstInsurance + itemSurcharges(step.items)) + PROCESSING_FEE;
78	};
79	
80	export const runScenario = (scenario: Scenario): { results: { premium: number }[] } => {
81	  const results = scenario.steps.map((step) => ({ premium: quotePremium(step) }));
82	  return { results };
83	};
